const express = require('express');
const winston = require('winston');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');

const app = express();

// Sanitization function to prevent log injection
function sanitizeLogInput(input) {
  if (typeof input !== 'string') {
    input = String(input);
  }
  
  // Remove newlines, carriage returns, and other control characters
  // that could be used for log injection attacks
  return input
    .replace(/[\n\r\t\v\f\0]/g, '')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .substring(0, 500); // Limit length to prevent log flooding
}

// Sanitize IP address
function sanitizeIP(ip) {
  if (!ip) return 'unknown';
  
  // Validate IPv4 or IPv6 format
  const ipv4Regex = /^(\d{1,3}\.){3}\d{1,3}$/;
  const ipv6Regex = /^([0-9a-fA-F]{0,4}:){2,7}[0-9a-fA-F]{0,4}$/;
  
  if (ipv4Regex.test(ip) || ipv6Regex.test(ip)) {
    return ip;
  }
  
  // If forwarded, take only the first IP and validate
  const firstIP = ip.split(',')[0].trim();
  if (ipv4Regex.test(firstIP) || ipv6Regex.test(firstIP)) {
    return firstIP;
  }
  
  return 'invalid';
}

// Allowlist for custom headers that can be logged
const ALLOWED_HEADERS = [
  'user-agent',
  'content-type',
  'accept',
  'x-request-id',
  'x-correlation-id'
];

// Winston logger configuration
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'audit-service' },
  transports: [
    new winston.transports.File({ 
      filename: 'logs/error.log', 
      level: 'error',
      maxsize: 10485760, // 10MB
      maxFiles: 5
    }),
    new winston.transports.File({ 
      filename: 'logs/audit.log',
      maxsize: 10485760,
      maxFiles: 10
    })
  ]
});

// Console logging for development only
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

// Morgan configuration with sanitization
morgan.token('sanitized-user', (req) => {
  return req.user ? sanitizeLogInput(req.user.username) : 'anonymous';
});

morgan.token('sanitized-ip', (req) => {
  const ip = req.ip || req.connection.remoteAddress;
  return sanitizeIP(ip);
});

morgan.token('sanitized-custom-header', (req) => {
  const customHeader = req.headers['x-custom-data'];
  return customHeader ? sanitizeLogInput(customHeader) : 'none';
});

// Morgan middleware with custom format
